<p>Seseorang yang berusia 17 tahun, dengan izin legal, dapat bekerja di toko ritel, restoran, pasar swalayan, bioskop, atau perusahaan event organizer.</p></p>', '$.wp_published_at', '2026-06-13T03:00:00Z', '$.wp_modified_at', '2026-03-14T16:07:33Z', '$.featured_image', json('{"provider":"external","src":"/wp-content/uploads/2025/02/international-students-in-turkey.webp","alt":"Social life for international students studying at universities in Turkey.","title":"international-students-in-turkey"}')) WHERE "collection" = 'posts' AND "id" = ( SELECT "live_revision_id" FROM "ec_posts" WHERE "deleted_at" IS NULL AND "status" = 'published' AND "locale" = 'id' AND "slug" = 'peluang-kerja-paruh-waktu-untuk-mahasiswa-di-turki' );
